// AI 처리가 필요한 영상 필터링 (description/comment 직접 매칭 없는 영상)
var videosResp = $('Get Active Videos').first().json;
var vpsResp = $('Get All VPs').first().json;

var videos = (videosResp && videosResp.list) ? videosResp.list : [];
var allVPs = (vpsResp && vpsResp.list) ? vpsResp.list : [];

// description/comment VPs가 있는 video_id 수집
var directVideoIds = {};
for (var i = 0; i < allVPs.length; i++) {
  var vp = allVPs[i];
  if (vp.source === 'description' || vp.source === 'comment') {
    directVideoIds[vp.video_id] = true;
  }
}

// AI 처리 대상: 직접 URL 매칭 없는 영상만
var toProcess = [];
for (var j = 0; j < videos.length; j++) {
  var v = videos[j];
  if (!directVideoIds[v.video_id]) {
    toProcess.push(v);
  }
}

return [{ json: { videos: toProcess, count: toProcess.length } }];

// 영상 배열을 개별 아이템으로 변환 (SplitInBatches 입력용)
var videos = $input.first().json.videos || [];
if (videos.length === 0) return [];
return videos.map(function(v) { return { json: v }; });

// Stage 1: Gemini 키워드 추출용 프롬프트 구성
var v = $input.first().json;
var title = v.title || '';
var desc = (v.description || '').substring(0, 600);
var tagsArr = [];
try { tagsArr = JSON.parse(v.tags || '[]'); } catch(e) { tagsArr = []; }
var matchedCat = v.matched_category || '';

var prompt = '당신은 한국 공예 재료 쇼핑몰 상품 매칭 전문가입니다.\n\n다음 YouTube 영상 정보에서 영상에서 사용된 핵심 재료명을 추출해 주세요.\n\n영상 제목: ' + title + '\n';
if (matchedCat) prompt += '감지된 카테고리: ' + matchedCat + '\n';
if (tagsArr.length > 0) prompt += '태그: ' + tagsArr.slice(0, 8).join(', ') + '\n';
if (desc) prompt += '영상 설명(일부): ' + desc + '\n';
prompt += '\n규칙:\n';
prompt += '1. 상품명으로 검색 가능한 정확한 재료명 추출\n';
prompt += '2. 예: "UV레진", "실리콘 몰드", "소이왁스", "LED 천스탠드", "압화 꽃 세트", "탈포기", "하바리움 용액"\n';
prompt += '3. 철자 주의: 스탠 vs 스텐 (LED 천스탠드가 올바름), 하바리움 용액/용기 정확히\n';
prompt += '4. 최대 5개 키워드 추출\n';
prompt += '5. "만들기", "영상", "강좌", "DIY" 등 일반 단어 제외\n';
prompt += '\nJSON으로만 응답하세요 (다른 텍스트 없이):\n';
prompt += '{"keywords": ["키워드1", "키워드2"], "category": "압화|레진|캔들|석고|비즈|기타"}';

return [{ json: { video_id: v.video_id, title: v.title, prompt: prompt } }];

// Stage 1: Gemini 응답 파싱 + 한국어 정규화 + 상품 점수 계산 → Top 20 후보 반환
var geminiResp = $input.first().json;
var buildData = $('Build Prompt').first().json;
var productsResp = $('Get All Products').first().json;
var vpsResp = $('Get All VPs').first().json;

var videoId = buildData.video_id;
var videoTitle = buildData.title || '';
var allProducts = (productsResp && productsResp.list) ? productsResp.list : [];
var allVPs = (vpsResp && vpsResp.list) ? vpsResp.list : [];

// 한국어 발음 정규화 (AI 오타/발음 오류 보정)
function normalize(s) {
  return (s || '').toLowerCase()
    .replace(/스텐/g, '스탠')
    .replace(/텐드/g, '탠드')
    .replace(/레짐/g, '레진')
    .replace(/켄들/g, '캔들')
    .replace(/에폭씨/g, '에폭시')
    .replace(/레즌/g, '레진')
    .replace(/하바륨/g, '하바리움');
}

// Gemini Stage 1 응답 파싱 (thinking mode: 여러 parts에서 텍스트 합산)
var keywords = [];
var aiCategory = '';
try {
  var cands = (geminiResp && geminiResp.candidates) ? geminiResp.candidates : [];
  if (cands.length > 0) {
    var text = '';
    var parts = (cands[0].content && cands[0].content.parts) ? cands[0].content.parts : [];
    for (var pi = 0; pi < parts.length; pi++) {
      if (parts[pi].text) text += parts[pi].text;
    }
    var jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      var parsed = JSON.parse(jsonMatch[0]);
      keywords = (parsed.keywords || []).filter(function(k) { return k && k.length >= 2; });
      aiCategory = parsed.category || '';
    }
  }
} catch(e) { keywords = []; }

// 기존 keyword/ai VP 비활성화 대상 수집
var deactivateBody = [];
for (var i = 0; i < allVPs.length; i++) {
  var vp = allVPs[i];
  if (vp.video_id === videoId && (vp.source === 'keyword' || vp.source === 'ai') && vp.is_active !== false) {
    deactivateBody.push({ Id: vp.Id, is_active: false });
  }
}

// 키워드 없으면 스킵 (기존 VP 유지)
if (keywords.length === 0) {
  return [{ json: { video_id: videoId, videoTitle: videoTitle, keywords: [], aiCategory: '', deactivateBody: [], matchCandidates: [], skip: true } }];
}

// 상품 점수 계산 (정규화 적용 후 키워드 매칭)
var scored = [];
for (var j = 0; j < allProducts.length; j++) {
  var prod = allProducts[j];
  var pname = normalize(prod.product_name || '');
  var score = 0;
  var matchedKws = [];
  for (var k = 0; k < keywords.length; k++) {
    var kw = normalize(keywords[k]);
    if (kw.length < 2) continue;
    if (pname.indexOf(kw) >= 0) {
      score += 5;
      matchedKws.push(keywords[k]);
    } else {
      var wparts = kw.split(/\s+/);
      for (var wp = 0; wp < wparts.length; wp++) {
        if (wparts[wp].length >= 2 && pname.indexOf(wparts[wp]) >= 0) {
          score += 2;
          if (matchedKws.indexOf(keywords[k]) < 0) matchedKws.push(keywords[k]);
        }
      }
    }
  }
  var pcat = normalize(prod.category_name || '');
  if (aiCategory && pcat.indexOf(normalize(aiCategory)) >= 0) score += 1;
  if (score > 0) scored.push({ score: score, prod: prod });
}
scored.sort(function(a, b) { return b.score - a.score; });
var top20 = scored.slice(0, 20);

// Stage 2에 전달할 후보 목록 구성
var matchCandidates = top20.map(function(item) {
  return {
    branduid: String(item.prod.branduid || ''),
    product_name: item.prod.product_name || '',
    product_price: item.prod.price || 0,
    product_image: item.prod.image_url || '',
    product_url: item.prod.product_url || ('/shop/shopdetail.html?branduid=' + item.prod.branduid),
    score: item.score
  };
});

return [{ json: { video_id: videoId, videoTitle: videoTitle, keywords: keywords, aiCategory: aiCategory, deactivateBody: deactivateBody, matchCandidates: matchCandidates, skip: false } }];

// Stage 2 프롬프트 구성: Top 20 후보 → Gemini에게 실제 사용 재료 선택 요청
var stage1 = $input.first().json;

// 후보 없거나 스킵 → Gemini에게 빈 응답 유도 프롬프트 전달
if (stage1.skip || !stage1.matchCandidates || stage1.matchCandidates.length === 0) {
  return [{ json: {
    video_id: stage1.video_id || '',
    videoTitle: stage1.videoTitle || '',
    keywords: stage1.keywords || [],
    aiCategory: stage1.aiCategory || '',
    deactivateBody: stage1.deactivateBody || [],
    matchCandidates: [],
    stage2Prompt: '다음 JSON을 그대로 출력하세요: {"matches": []}',
    skip: true
  } }];
}

var title = stage1.videoTitle || '';
var candidates = stage1.matchCandidates;

var prodLines = candidates.map(function(c, idx) {
  return (idx + 1) + '. branduid=' + c.branduid + ' | ' + c.product_name;
}).join('\n');

var prompt = '당신은 한국 공예 쇼핑몰 상품 추천 전문가입니다.\n\n';
prompt += '영상 제목: ' + title + '\n';
prompt += 'AI 감지 키워드: ' + stage1.keywords.join(', ') + '\n\n';
prompt += '=== 후보 상품 목록 ===\n';
prompt += prodLines + '\n\n';
prompt += '선택 기준:\n';
prompt += '1. 영상에서 실제로 손으로 사용하는 핵심 재료/도구 우선 선택\n';
prompt += '2. 완성 작품(완성 액자, 완성 부케, 작품집, 책, 완성 키링) 제외 - 원재료/용기/공구만 선택\n';
prompt += '3. 영상 메인 주제 상품을 1순위로\n';
prompt += '4. 카테고리 매칭: 하바리움 영상에는 하바리움 용기/용액, 천스탠드 영상에는 LED 천스탠드 우선\n';
prompt += '5. 최대 4개 선택\n\n';
prompt += 'JSON으로만 응답 (다른 텍스트 없이):\n';
prompt += '{"matches": [{"branduid": "값", "reason": "선택이유"}]}\n';
prompt += '위 후보 목록에 없는 branduid는 절대 포함하지 마세요.';

return [{ json: {
  video_id: stage1.video_id,
  videoTitle: title,
  keywords: stage1.keywords,
  aiCategory: stage1.aiCategory,
  deactivateBody: stage1.deactivateBody,
  matchCandidates: candidates,
  stage2Prompt: prompt,
  skip: false
} }];

// Stage 2 파싱: Gemini 선택 결과 → 최종 insertBody 구성
var stage2Data = $('Build Catalog Prompt').first().json;
var geminiResp = $input.first().json;

var videoId = stage2Data.video_id;
var deactivateBody = stage2Data.deactivateBody || [];
var matchCandidates = stage2Data.matchCandidates || [];

// skip 또는 후보 없음 → 아무것도 변경하지 않음
if (stage2Data.skip || matchCandidates.length === 0) {
  return [{ json: { video_id: videoId, insertBody: [], deactivateBody: [], skip: true } }];
}

// 후보 맵 구성 (branduid → 상품 정보)
var candMap = {};
matchCandidates.forEach(function(c) { candMap[String(c.branduid)] = c; });

// Gemini Stage 2 응답 파싱 (thinking mode: 여러 parts 합산)
var matchedBranduids = [];
try {
  var candidates = (geminiResp && geminiResp.candidates) ? geminiResp.candidates : [];
  if (candidates.length > 0) {
    var text = '';
    var parts = (candidates[0].content && candidates[0].content.parts) ? candidates[0].content.parts : [];
    for (var pi = 0; pi < parts.length; pi++) {
      if (parts[pi].text) text += parts[pi].text;
    }
    var jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      var parsed = JSON.parse(jsonMatch[0]);
      var matches = parsed.matches || [];
      matches.forEach(function(m) {
        var buid = String(m.branduid || '');
        if (buid && candMap[buid] && matchedBranduids.indexOf(buid) < 0) {
          matchedBranduids.push(buid);
        }
      });
    }
  }
} catch(e) { matchedBranduids = []; }

// Stage 2 실패 시 Stage 1 Top 4로 폴백
if (matchedBranduids.length === 0) {
  matchedBranduids = matchCandidates.slice(0, 4).map(function(c) { return c.branduid; });
}

// 최종 삽입 데이터 구성 (최대 4개)
var insertBody = matchedBranduids.slice(0, 4).map(function(buid, idx) {
  var c = candMap[buid];
  return {
    video_id: videoId,
    branduid: buid,
    product_name: c.product_name,
    product_price: c.product_price,
    product_image: c.product_image,
    product_url: c.product_url,
    source: 'ai',
    confidence: 'medium',
    match_score: c.score,
    display_order: idx + 1,
    is_active: true,
    matched_at: new Date().toISOString()
  };
});

return [{ json: { video_id: videoId, insertBody: insertBody, deactivateBody: deactivateBody, skip: false } }];
